<?php
namespace App\Domain\Combat;use App\Domain\Combat\Data\CombatMitigationConfig;use App\Domain\Combat\Data\DamageMitigationResult;use InvalidArgumentException;
final class CombatDamageMitigationService{public function mitigate($incoming,$attack,$defense,$absorb,CombatMitigationConfig $config){if(!is_numeric($incoming)||!is_int($attack)||!is_int($defense)||!is_int($absorb))throw new InvalidArgumentException('Invalid damage mitigation input types.');if($incoming<0||$attack<0||$defense<0||$absorb<0)throw new InvalidArgumentException('Damage mitigation inputs cannot be negative.');if($defense>PHP_INT_MAX-$attack)throw new InvalidArgumentException('Damage mitigation overflow.');$denominator=$attack+$defense;$rawDefense=$denominator===0?0:(int)floor($defense*10000/$denominator);$appliedDefense=min($rawDefense,$config->defenseReductionCapBasisPoints());$appliedAbsorb=min($absorb,$config->absorbDamageCapBasisPoints());$afterDefense=$incoming*(10000-$appliedDefense)/10000;$afterAbsorb=$afterDefense*(10000-$appliedAbsorb)/10000;$byCap=$incoming*(10000-$config->totalMitigationCapBasisPoints())/10000;$unrounded=max($afterAbsorb,$byCap,(float)$config->minimumDamage());$final=max($config->minimumDamage(),(int)round($unrounded));return new DamageMitigationResult(['incoming_damage'=>$incoming,'raw_defense_reduction_basis_points'=>$rawDefense,'applied_defense_reduction_basis_points'=>$appliedDefense,'damage_after_defense'=>$afterDefense,'raw_absorb_basis_points'=>$absorb,'applied_absorb_basis_points'=>$appliedAbsorb,'damage_after_absorb'=>$afterAbsorb,'minimum_damage_by_total_cap'=>$byCap,'final_damage'=>$final]);}}
